// ===== HELPERS =====
function getTaskName(item) {
  const props = item.json.properties || {};
  const nameProps = ['Name', 'Task', 'Title', 'name', 'title'];
  for (const key of nameProps) {
    if (props[key] && props[key].title && Array.isArray(props[key].title) && props[key].title.length > 0) {
      return props[key].title.map(t => t.plain_text || '').join('').trim();
    }
  }
  for (const key of Object.keys(props)) {
    const p = props[key];
    if (p && p.type === 'title' && Array.isArray(p.title) && p.title.length > 0) {
      return p.title.map(t => t.plain_text || '').join('').trim();
    }
  }
  return '(sem nome)';
}

function getTags(item) {
  const props = item.json.properties || {};
  const tagProps = ['Tags', 'Tag', 'Labels'];
  for (const key of tagProps) {
    if (props[key]) {
      if (props[key].multi_select) return props[key].multi_select.map(t => t.name);
      if (props[key].select && props[key].select.name) return [props[key].select.name];
    }
  }
  return [];
}

function getDueDate(item) {
  const props = item.json.properties || {};
  const dateProps = ['Due Date', 'Due', 'Date', 'Deadline'];
  for (const key of dateProps) {
    if (props[key] && props[key].date && props[key].date.start) {
      return props[key].date.start;
    }
  }
  return '';
}

function getProjectId(item) {
  const props = item.json.properties || {};
  const projProps = ['Project', 'Projects'];
  for (const key of projProps) {
    if (props[key] && props[key].relation && props[key].relation.length > 0) {
      return props[key].relation[0].id;
    }
  }
  return '';
}

function getProjectType(item) {
  const props = item.json.properties || {};
  const typeProps = ['Type', 'Tipo', 'Category'];
  for (const key of typeProps) {
    if (props[key]) {
      if (props[key].select && props[key].select.name) return props[key].select.name;
    }
  }
  return '';
}

function getContext(tags) {
  if (tags.includes('Brasil')) return '🇧🇷';
  if (tags.includes('Portugal')) return '🇵🇹';
  return '';
}

function getDependency(tags) {
  if (tags.includes('Dependo de Terceiros')) return '⏸️';
  return '';
}

function getNightShiftDate() {
  const now = new Date();
  const lisbonNowStr = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Lisbon',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    hour12: false
  }).format(now);
  const [datePart, timePart] = lisbonNowStr.split(', ');
  const hourLisbon = parseInt(timePart, 10);

  let reportDate = datePart;
  if (hourLisbon < 6) {
    const d = new Date(datePart + 'T12:00:00Z');
    d.setUTCDate(d.getUTCDate() - 1);
    reportDate = d.toISOString().slice(0, 10);
  }
  return reportDate;
}

function getWeekdayLisbon(dateStr) {
  const d = new Date(dateStr + 'T12:00:00Z');
  const fmt = new Intl.DateTimeFormat('pt-PT', {
    timeZone: 'Europe/Lisbon',
    weekday: 'long'
  });
  const day = fmt.format(d).toLowerCase();
  const map = {
    'domingo': 'Domingo',
    'segunda-feira': 'Segunda',
    'terça-feira': 'Terca',
    'quarta-feira': 'Quarta',
    'quinta-feira': 'Quinta',
    'sexta-feira': 'Sexta',
    'sábado': 'Sabado'
  };
  return map[day] || day;
}

// ===== GET TODAY DAILY SUMMARY (CRIADO PELO ARY ANTES DAS 22h) =====
let todaySummary = '';
let todayScoreFromSummary = null;
let hasSummaryForToday = false;
try {
  const summaryNode = $('Get Today Summary').first().json;
  if (summaryNode && summaryNode.found && summaryNode.entries && summaryNode.entries.length > 0) {
    const entry = summaryNode.entries[0];
    const dateTag = (entry.tags || []).find(t => /^\d{4}-\d{2}-\d{2}$/.test(t)) || 'data desconhecida';
    todaySummary = `\n\nDAILY SUMMARY DE HOJE (${dateTag}) — criado pelo Ary antes desta execucao:\n${entry.details || entry.summary}\n`;
    hasSummaryForToday = true;
    const scoreMatch = (entry.details || '').match(/SCORE_?DO_?DIA:\s*(\d+(?:\.\d+)?)\s*\/\s*10/i);
    if (scoreMatch) todayScoreFromSummary = parseFloat(scoreMatch[1]);
  } else {
    todaySummary = '\n\n⚠️ Ary NAO criou daily summary de hoje antes desta execucao. NAO disse boa noite ate as 22h.\n';
  }
} catch(e) {
  todaySummary = '\n\n(Erro a obter daily summary de hoje)\n';
}

// ===== BUILD PROJECT LOOKUP MAP =====
const projectItems = $('Active Projects').all();
const projectMap = {};
for (const p of projectItems) {
  const id = p.json.id;
  const name = getTaskName(p);
  const type = getProjectType(p);
  projectMap[id] = { name, type };
}

function getProjectName(item) {
  const id = getProjectId(item);
  if (!id) return '';
  if (projectMap[id]) return projectMap[id].name;
  return '(unknown project)';
}

function getProjectNameById(id) {
  if (!id) return '';
  if (projectMap[id]) return projectMap[id].name;
  return '';
}

// ===== DATE REFERENCES =====
const today = getNightShiftDate();
const weekday = getWeekdayLisbon(today);

const todayD = new Date(today + 'T12:00:00Z');
todayD.setUTCDate(todayD.getUTCDate() + 1);
const tomorrow = todayD.toISOString().slice(0, 10);
const tomorrowWeekday = getWeekdayLisbon(tomorrow);

const [ty, tm, td] = today.split('-');
const todayDisplay = `${td}/${tm}/${ty}`;

// ===== SNAPSHOT DIFF (NEW IN v3) =====
let diffSection = '';
let snapshotTodayCount = 0;
let snapshotYesterdayCount = 0;
let diffCompleted = [];
let diffCreated = [];
let diffRescheduled = [];

try {
  // Snapshot de hoje — cross-branch via $()
  let todaySnapshotTasks = [];
  try {
    const todaySnapshotNode = $('Build Snapshot Payload').first().json;
    if (todaySnapshotNode && todaySnapshotNode.details) {
      const payload = JSON.parse(todaySnapshotNode.details);
      todaySnapshotTasks = payload.tasks || [];
      snapshotTodayCount = payload.total_pending_in_notion || todaySnapshotTasks.length;
    }
  } catch (e) {
    todaySnapshotTasks = [];
  }

  // Snapshot de ontem — via Get Yesterday Snapshot node
  let yesterdaySnapshotTasks = [];
  try {
    const yesterdaySnapshotNode = $('Get Yesterday Snapshot').first().json;
    if (yesterdaySnapshotNode && yesterdaySnapshotNode.found && yesterdaySnapshotNode.entries && yesterdaySnapshotNode.entries.length > 0) {
      const entry = yesterdaySnapshotNode.entries[0];
      const payload = JSON.parse(entry.details);
      yesterdaySnapshotTasks = payload.tasks || [];
      snapshotYesterdayCount = payload.total_pending_in_notion || yesterdaySnapshotTasks.length;
    }
  } catch (e) {
    yesterdaySnapshotTasks = [];
  }

  // Computar diff
  if (yesterdaySnapshotTasks.length > 0) {
    const todayIds = new Set(todaySnapshotTasks.map(t => t.id));
    const yesterdayIds = new Set(yesterdaySnapshotTasks.map(t => t.id));
    const todayMap = new Map(todaySnapshotTasks.map(t => [t.id, t]));
    const yesterdayMap = new Map(yesterdaySnapshotTasks.map(t => [t.id, t]));

    // COMPLETED: estavam ontem (no relevante), não estão hoje (mas existem no Notion como Done OU foram apagadas)
    for (const yt of yesterdaySnapshotTasks) {
      if (!todayIds.has(yt.id)) {
        diffCompleted.push(yt);
      }
    }

    // CREATED: estão hoje, não estavam ontem
    for (const tt of todaySnapshotTasks) {
      if (!yesterdayIds.has(tt.id)) {
        diffCreated.push(tt);
      }
    }

    // RESCHEDULED: mesmo id, due_date diferente
    for (const tt of todaySnapshotTasks) {
      const yt = yesterdayMap.get(tt.id);
      if (yt && yt.due_date !== tt.due_date) {
        diffRescheduled.push({ task: tt, old_due: yt.due_date, new_due: tt.due_date });
      }
    }

    // Formatar secção
    const lines = [];
    lines.push(`MOVIMENTO DE TASKS (snapshot ontem ${snapshotYesterdayCount} → hoje ${snapshotTodayCount}):`);

    if (diffCompleted.length > 0) {
      lines.push(`\n✅ SAIRAM DO RADAR (${diffCompleted.length}) — concluidas ou apagadas:`);
      diffCompleted.slice(0, 10).forEach(t => {
        const proj = getProjectNameById(t.project_id);
        const projTag = proj ? ` [${proj}]` : '';
        lines.push(`  - ${t.name}${projTag}`);
      });
      if (diffCompleted.length > 10) lines.push(`  ... +${diffCompleted.length - 10} mais`);
    }

    if (diffCreated.length > 0) {
      lines.push(`\n🆕 CRIADAS HOJE (${diffCreated.length}):`);
      diffCreated.slice(0, 10).forEach(t => {
        const proj = getProjectNameById(t.project_id);
        const projTag = proj ? ` [${proj}]` : '';
        const prio = t.priority === 'Alta' ? '🔴' : t.priority === 'Media' ? '🟡' : '⚪';
        const due = t.due_date ? ` (due: ${t.due_date})` : '';
        lines.push(`  ${prio} ${t.name}${projTag}${due}`);
      });
      if (diffCreated.length > 10) lines.push(`  ... +${diffCreated.length - 10} mais`);
    }

    if (diffRescheduled.length > 0) {
      lines.push(`\n🔄 REAGENDADAS (${diffRescheduled.length}):`);
      diffRescheduled.slice(0, 10).forEach(r => {
        const proj = getProjectNameById(r.task.project_id);
        const projTag = proj ? ` [${proj}]` : '';
        const oldD = r.old_due || '(sem data)';
        const newD = r.new_due || '(sem data)';
        lines.push(`  - ${r.task.name}${projTag}: ${oldD} → ${newD}`);
      });
      if (diffRescheduled.length > 10) lines.push(`  ... +${diffRescheduled.length - 10} mais`);
    }

    if (diffCompleted.length === 0 && diffCreated.length === 0 && diffRescheduled.length === 0) {
      lines.push(`(sem movimento — tasks identicas a ontem)`);
    }

    diffSection = '\n\n' + lines.join('\n') + '\n';
  } else {
    diffSection = `\n\nMOVIMENTO DE TASKS: (sem snapshot de ontem para comparar — primeiro dia do sistema OU snapshot expirado)\n`;
  }
} catch (e) {
  diffSection = `\n\n(Erro a calcular diff: ${e.message})\n`;
}

// ===== FILTRO DONE HOJE =====
function isEditedTodayLisbon(item) {
  const edited = item.json.last_edited_time || '';
  if (!edited) return false;
  const d = new Date(edited);
  if (isNaN(d.getTime())) return false;
  const editedDayPT = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Lisbon',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).format(d);
  return editedDayPT === today;
}

const doneItems = $('Tasks Done Last 30 Days').all().filter(i => {
  const props = i.json.properties || {};
  if (Object.keys(props).length === 0) return false;
  return isEditedTodayLisbon(i);
});

const doneToday = doneItems.map(i => {
  const name = getTaskName(i);
  const project = getProjectName(i);
  const tags = getTags(i);
  const ctx = getContext(tags);
  const projectTag = project ? ` [${project}]` : '';
  const ctxTag = ctx ? ` ${ctx}` : '';
  return `${name}${projectTag}${ctxTag}`;
}).join('\n');
const doneCount = doneItems.length;

// ===== OVERDUE =====
// PATCH 2026-05-30: separar vencidas estritas (Due < today) de para-hoje (Due == today)
const overdueRawItems = $('Tasks Overdue').all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});

const overdueItems = overdueRawItems.filter(i => {
  const due = getDueDate(i);
  return due && due < today;
});
const dueTodayItems = overdueRawItems.filter(i => {
  const due = getDueDate(i);
  return due && due === today;
});

const overdue = overdueItems.map(i => {
  const name = getTaskName(i);
  const due = getDueDate(i);
  const project = getProjectName(i);
  const tags = getTags(i);
  const prio = tags.includes('Prioridade Alta') ? '🔴'
    : (tags.includes('Prioridade Média') || tags.includes('Prioridade Media')) ? '🟡'
    : '⚪';
  const ctx = getContext(tags);
  const dep = getDependency(tags);
  const flags = [ctx, dep].filter(x => x).join(' ');
  const projectTag = project ? ` [${project}]` : '';
  const flagsTag = flags ? ` ${flags}` : '';
  const dueD = new Date(due + 'T12:00:00Z');
  const todayD2 = new Date(today + 'T12:00:00Z');
  const daysOverdue = Math.floor((todayD2 - dueD) / (1000 * 60 * 60 * 24));
  const daysTag = daysOverdue > 0 ? ` (${daysOverdue}d atrasada)` : '';
  return `${prio} ${name}${projectTag}${flagsTag} (due: ${due})${daysTag}`;
}).join('\n');
const overdueCount = overdueItems.length;
const dueTodayCount = dueTodayItems.length;

const antiStreakItems = overdueItems.filter(i => {
  const due = getDueDate(i);
  if (!due) return false;
  const dueD = new Date(due + 'T12:00:00Z');
  const todayD2 = new Date(today + 'T12:00:00Z');
  const days = Math.floor((todayD2 - dueD) / (1000 * 60 * 60 * 24));
  return days >= 3;
});
const antiStreakCount = antiStreakItems.length;
// ===== ARCHIVE CANDIDATES (PATCH 2) =====
// Critério objectivo: overdue + last_edited > 30d + priority != Alta
const archiveCandidatesItems = overdueItems.filter(i => {
  const lastEdited = i.json.last_edited_time || '';
  if (!lastEdited) return false;
  const editedD = new Date(lastEdited);
  if (isNaN(editedD.getTime())) return false;
  const daysSinceEdit = Math.floor((new Date() - editedD) / (1000 * 60 * 60 * 24));
  const tags = getTags(i);
  const isAlta = tags.includes('Prioridade Alta');
  return daysSinceEdit > 30 && !isAlta;
});

const archiveCandidates = archiveCandidatesItems.map(i => {
  const name = getTaskName(i);
  const project = getProjectName(i);
  const lastEdited = i.json.last_edited_time || '';
  const daysSinceEdit = Math.floor((new Date() - new Date(lastEdited)) / (1000 * 60 * 60 * 24));
  const projectTag = project ? ` [${project}]` : '';
  return `- ${name}${projectTag} (${daysSinceEdit}d sem edit)`;
}).join('\n');
const archiveCandidatesCount = archiveCandidatesItems.length;
// ===== NEXT 7 DAYS =====
const next7Items = $('Tasks Next 7 Days').all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});

const next7Days = next7Items.map(i => {
  const name = getTaskName(i);
  const due = getDueDate(i);
  const project = getProjectName(i);
  const tags = getTags(i);
  const prio = tags.includes('Prioridade Alta') ? '🔴'
    : (tags.includes('Prioridade Média') || tags.includes('Prioridade Media')) ? '🟡'
    : '⚪';
  const ctx = getContext(tags);
  const dep = getDependency(tags);
  const flags = [ctx, dep].filter(x => x).join(' ');
  const projectTag = project ? ` [${project}]` : '';
  const flagsTag = flags ? ` ${flags}` : '';
  return `${prio} ${name}${projectTag}${flagsTag} (${due})`;
}).join('\n');
const next7Count = next7Items.length;

// ===== PROMPT =====
const prompt = `Hoje terminou ${todayDisplay}, ${weekday}. Night Shift para Ary Ribeiro.

CONTEXTO: Consultor IA, 3 verticais: TJ (advogados BR R$2.997/mes), TM (clinicas BR R$2.997/mes), CL (imobiliarias PT E497/mes). Meta Q2: E12.857 trimestral. Foco actual: construcao da maquina (consistencia de conteudos), Sales suspenso ate 11 Jun 2026.

REGRA TEMPORAL CRITICA: O daily summary DE HOJE foi criado pelo Ary antes desta execucao (ele disse "boa noite" ao Ops Manager ate as 22h). Se nao houver daily summary de hoje (campo vazio abaixo), o Ary nao fez o fechamento do dia — isto e um sinal de fricao na rotina de higiene de sono.
${todaySummary}
O QUE FOI REALMENTE FEITO HOJE (${doneCount} tasks Notion concluidas):
${doneToday || '(ZERO tasks Notion concluidas hoje — mas pode haver trabalho registado no daily summary acima)'}
${diffSection}
TASKS ATRASADAS (${overdueCount}${antiStreakCount > 0 ? ', ' + antiStreakCount + ' ha 3+ dias' : ''}):
${overdue || '(nenhuma task atrasada)'}
ARCHIVE CANDIDATES (criterio: overdue + last_edited > 30d + priority != Alta):
${archiveCandidates || '(nenhum candidato objectivo)'}
[total: ${archiveCandidatesCount}]
TASKS PROXIMOS 7 DIAS (${next7Count}):
${next7Days || '(nenhuma task agendada)'}

LEGENDA: 🔴 Alta | 🟡 Media | ⚪ Baixa/sem | 🇧🇷 Brasil | 🇵🇹 Portugal | ⏸️ Dependo de terceiros

ANALISA e gera o Night Shift Report:

═══ HARD CONSTRAINTS DE INTEGRIDADE DE DADOS ═══

HC1 - ANTI CROSS-CONTAMINATION TEMPORAL:
O Brain MCP pode retornar daily summaries de dias anteriores como contexto.
NUNCA copiar valores numericos (sono, horas trabalho, doses, jejum) de daily
summaries antigos como se fossem do dia actual. Cada valor numerico DESTE report
deve ter origem comprovavel no daily summary DE HOJE (acima). Se um campo so
existe em summary de dia anterior, NAO o reportar como facto de hoje.

HC2 - ANTI INFERENCIA POR PADRAO TIPICO:
Para sono, jejum alimentar, e nutricao: se o daily summary de hoje NAO mencionar
explicitamente esses dados (com numero concreto), NAO inferir baseado em
"Ary normalmente dorme X" ou "rotina tipica". Escrever literalmente:
"sleep_hours nao reportado no daily summary" ou similar.
Yoga, meditacao, treino: aceitar como facto se o daily summary disser
explicitamente que foram feitos.

HC3 - VERIFICACAO DE SUPLEMENTOS CONTRA PROTOCOLO:
Protocolo 2026 (referencia da memory entry e9b6bbd5):
  CoQ10 200mg meal | Cindura 800mg pre-workout | Cafeina 200mg pre-workout
  HMB 3g pre-workout | Creatina 5g pre-workout | Whey 30g post-workout
  PeptiStrong 2.4g post-workout | Magnesio 400mg evening

Se o daily summary listar doses tomadas:
- Comparar cada dose vs protocolo
- Se desvio > 15%: sinalizar literalmente, ex: "HMB 1000mg vs protocolo 3000mg (-67%)"
- Se suplemento do protocolo nao for mencionado: "Creatina nao reportada (protocolo: 5g pre-workout)"
- NUNCA dizer "X suplementos correctos" sem ter comparado contra protocolo.
- Se daily summary nao detalhar doses: dizer "doses nao detalhadas no summary, validacao impossivel".

HC4 - AUDITABILIDADE DE NUMEROS NOTION:
Quando reportar contagens de tasks, usar EXACTAMENTE os valores pre-calculados.
NUNCA arredondar, aproximar ou inferir. Valores disponiveis:
  overdueCount=${overdueCount} (Due < hoje AND Status != Done, ESTRITO)
  dueTodayCount=${dueTodayCount} (Due = hoje AND Status != Done)
  antiStreakCount=${antiStreakCount} (subset de overdueCount com 3+ dias)
  doneCount=${doneCount} (Done editado hoje)
  next7Count=${next7Count} (Due > hoje AND <= hoje+7d)
Reporta-los literais. Se o valor nao estiver claro no contexto acima, escrever "N/A".
NUNCA copiar contagens de daily summaries de dias anteriores como se fossem de hoje.

HC5 - DIFF E PROXY DE EXECUCAO OBJECTIVA (NEW v3):
A seccao "MOVIMENTO DE TASKS" mostra o que mudou entre snapshot de ontem e hoje.
Esta e a unica metrica OBJECTIVA de execucao (cruza com doneCount mas nao depende
do Ary editar last_edited_time). Diff_completed=${diffCompleted.length},
diff_created=${diffCreated.length}, diff_rescheduled=${diffRescheduled.length}.

- Se diff_completed > doneCount: tasks fecharam sem editar last_edited (suspeita de
  bulk-edit ou archive sem completar individualmente). Sinalizar.
- Se diff_rescheduled > 5: padrao de procrastinacao (Ary empurra prazos em massa).
  Identificar quais tasks foram empurradas e sinalizar como sinal de friccao.
- Se diff_created > 10: Ary esta a criar mais tasks do que fecha. Anti-padrao
  classico (backlog inflation). Apontar.
HC6 - GROUNDING DE BULK ACTIONS:
Quando sugerir archive/reschedule/triage em massa, listar IDs ou nomes concretos
da seccao ARCHIVE CANDIDATES acima. NUNCA escrever "archive 5+" ou "triagem brutal"
sem listar os candidatos especificos. Se ARCHIVE CANDIDATES for vazio
(archiveCandidatesCount=${archiveCandidatesCount}), NAO sugerir archive — escrever
literalmente "sem candidatos objectivos a archive hoje".
═══════════════════════════════════════════════
REGRAS:
1. ATE 11 JUN 2026: NAO cobrar Sales/pipeline/outreach. Foco em consistencia de conteudos.
2. SE existe DAILY SUMMARY DE HOJE: usar o score do Ary (${todayScoreFromSummary !== null ? todayScoreFromSummary + '/10' : 'N/A'}) como referencia. Tu podes concordar ou discordar (justificar). Cruzar tasks done Notion com sessoes time_log do daily summary — devem alinhar.
3. SE NAO existe daily summary de hoje: flag em destaque "Ary nao fechou o dia ate as 22h — risco de higiene de sono". NAO dar pre-brief sem fechamento — pedir para criar daily summary primeiro.
4. Se ha tasks atrasadas: identifica PORQUE nao foram concluidas (grande demais? nao sabe por onde comecar? nao e realmente prioridade?).
5. Se a mesma task esta atrasada ha 3+ dias (anti-streak detectado: ${antiStreakCount} tasks): NAO repitas a instrucao. DECOMPOE em micro-tasks de 30min cada.
6. AO REPORTAR TASKS ATRASADAS EM QUALQUER SECCAO: usar SEMPRE o formato "${overdueCount} vencidas (${antiStreakCount} ha 3+ dias) + ${dueTodayCount} para hoje". NUNCA reportar so um dos numeros isolado. overdueCount conta Due ESTRITAMENTE < hoje (vencidas reais); dueTodayCount conta Due = hoje (para hoje, ainda nao vencidas); antiStreakCount e o subconjunto de overdueCount com 3+ dias de atraso. Se dueTodayCount=0, omitir essa parte. Apresentar os numeros separadamente evita confundir "para hoje" com "vencido".
7. Tasks com ⏸️ Dependo de Terceiros: NAO contar como falha do Ary — flag separadamente.
8. SCORE proprio do dia (0-10): tu calculas baseado em (a) tasks done sem ⏸️ vs urgencia, (b) rotina 2026 cumprida (do daily summary), (c) consistencia de conteudos, (d) diff_completed vs diff_created (sinal de execucao real vs backlog inflation). Comparar com score do Ary se houver. OBRIGATORIO: a PRIMEIRA linha do teu output deve ser exactamente "SCORE_DO_DIA: N/10" (substitui N pelo numero que calculaste, ex 6.5). Esta linha e lida por outro sistema e nao pode faltar.
9. PRE-BRIEF para amanha (${tomorrowWeekday}): baseado no score, tasks dos proximos 7 dias, e padroes detectados.
10. Se score < 5: pre-brief deve DECOMPOR a task #1 em passos de 30min.
11. Se score >= 8: pre-brief mantem o plano.
12. Brutalmente honesto, zero fluff, tom de accountability partner.
13. RECOMENDACAO FINAL: lembrar Ary de baixar luminosidade da tela e sair do PC apos ler este report.

FORMATO:

SCORE_DO_DIA: [X/10]
${hasSummaryForToday ? 'FECHAMENTO DO DIA: ✅ Ary fechou o dia antes das 22h.' : '⚠️ FECHAMENTO DO DIA: NAO FEITO. Criar daily summary AGORA antes de dormir.'}

SCORE DO DIA (Claude vs Ary)
- Claude: [X/10] ${todayScoreFromSummary !== null ? '| Ary: ' + todayScoreFromSummary + '/10' : ''}
- [se diferenca >= 2: justificar]

EXECUCAO
- [cruzar tasks done Notion vs sessoes time_log do daily summary, identificar discrepancias]
- [comentar diff: ${diffCompleted.length} saidas, ${diffCreated.length} entradas, ${diffRescheduled.length} reagendadas]

ANTI-STREAK [so se ${antiStreakCount} > 0]
