function getTaskName(item) {
  const props = item.json.properties || {};
  for (const key of Object.keys(props)) {
    const p = props[key];
    if (p && p.type === 'title' && Array.isArray(p.title) && p.title.length > 0) {
      return p.title.map(t => t.plain_text || '').join('').trim();
    }
  }
  return '(sem nome)';
}

function getDueDate(item) {
  const props = item.json.properties || {};
  if (props['Due Date'] && props['Due Date'].date && props['Due Date'].date.start) {
    return props['Due Date'].date.start;
  }
  return null;
}

function getStatus(item) {
  const props = item.json.properties || {};
  if (props['Done?'] && props['Done?'].status && props['Done?'].status.name) {
    return props['Done?'].status.name;
  }
  return 'Unknown';
}

function getPriority(item) {
  const props = item.json.properties || {};
  if (props['Tags'] && props['Tags'].multi_select) {
    const tags = props['Tags'].multi_select.map(t => t.name);
    if (tags.includes('Prioridade Alta')) return 'Alta';
    if (tags.includes('Prioridade Média') || tags.includes('Prioridade Media')) return 'Media';
    if (tags.includes('Prioridade Baixa')) return 'Baixa';
  }
  return 'Sem';
}

function getDependency(item) {
  const props = item.json.properties || {};
  if (props['Tags'] && props['Tags'].multi_select) {
    return props['Tags'].multi_select.some(t => t.name === 'Dependo de Terceiros');
  }
  return false;
}

function getProjectId(item) {
  const props = item.json.properties || {};
  if (props['Project'] && props['Project'].relation && props['Project'].relation.length > 0) {
    return props['Project'].relation[0].id;
  }
  return null;
}

function getTodayLisbon() {
  const now = new Date();
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Lisbon',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).format(now);
}

function isRelevant(task, todayStr) {
  const today = new Date(todayStr + 'T00:00:00Z');
  const minDate = new Date(today); minDate.setDate(minDate.getDate() - 7);
  const maxDate = new Date(today); maxDate.setDate(maxDate.getDate() + 14);

  if (task.status === 'In progress') return true;
  if (task.priority === 'Alta') return true;
  if (task.due_date) {
    const d = new Date(task.due_date + 'T00:00:00Z');
    if (d >= minDate && d <= maxDate) return true;
  }
  return false;
}

const today = getTodayLisbon();

const allItems = $input.all().filter(i => {
  const props = i.json.properties || {};
  return Object.keys(props).length > 0;
});

const rawTasks = allItems.map(i => ({
  id: i.json.id,
  name: getTaskName(i),
  due_date: getDueDate(i),
  status: getStatus(i),
  priority: getPriority(i),
  depends_on_third_party: getDependency(i),
  project_id: getProjectId(i),
  last_edited: i.json.last_edited_time || null
}));

// DEDUP por id
const seenIds = new Set();
const allTasks = rawTasks.filter(t => {
  if (!t.id || seenIds.has(t.id)) return false;
  seenIds.add(t.id);
  return true;
});

const relevantTasks = allTasks.filter(t => isRelevant(t, today));

// PATCH 2026-05-30: subset estrito de vencidas (Due < today AND status != Done)
const overdueStrictTasks = allTasks.filter(t => {
  if (!t.due_date) return false;
  if (t.status === 'Done') return false;
  return t.due_date < today;
});

const payload = {
  snapshot_date: today,
  task_count: relevantTasks.length,
  total_pending_in_notion: allTasks.length,
  overdue_strict: overdueStrictTasks.length,
  raw_items_received: rawTasks.length,
  dedup_multiplier: rawTasks.length > 0 ? Math.round(rawTasks.length / Math.max(allTasks.length, 1) * 10) / 10 : 1,
  filter_rules: 'due_date in [today-7d, today+14d] OR priority=Alta OR status=In progress',
  overdue_strict_rule: 'due_date < today AND status != Done',
  tasks: relevantTasks
};

return [{
  json: {
    summary: `Notion snapshot ${today}: ${relevantTasks.length} relevantes, ${overdueStrictTasks.length} vencidas, ${allTasks.length} pendentes total`,
    details: JSON.stringify(payload, null, 2),
    source: 'NightShift',
    type: 'Fact',
    project: 'Ops',
    importance: '2',
    tags: JSON.stringify(['notion-snapshot', `notion-snapshot:${today}`, 'auto'])
  }
}];
